   238  func shouldIgnore(a admission.Attributes) bool {
   239          if a.GetResource().GroupResource() != api.Resource("pods") || (a.GetSubresource() != "" && a.GetSubresource() != "ephemeralcontainers") {
   240                  return true
   241          }
   242          obj := a.GetObject()
   243          if obj == nil {
   244                  return true
   245          }
   246          _, ok := obj.(*api.Pod)
   247          if !ok {
   248                  return true
   249          }
   250
   251          return false
   252  }
